const TUTORIAL_PREFERENCES_STORAGE_KEY = 'recludeTutorialPreferencesV1';
const defaultPreferences = () => ({
    hasSeenIntro: false,
    hideOnStartup: false,
});
export const loadTutorialPreferences = () => {
    try {
        const rawValue = localStorage.getItem(TUTORIAL_PREFERENCES_STORAGE_KEY);
        if (!rawValue) {
            return defaultPreferences();
        }
        const parsed = JSON.parse(rawValue);
        const preferences = {
            hasSeenIntro: parsed.hasSeenIntro === true,
            hideOnStartup: parsed.hideOnStartup === true,
        };
        if (typeof parsed.lastCompletedAt === 'string') {
            preferences.lastCompletedAt = parsed.lastCompletedAt;
        }
        return preferences;
    }
    catch (_error) {
        return defaultPreferences();
    }
};
export const saveTutorialPreferences = (nextPreferences) => {
    localStorage.setItem(TUTORIAL_PREFERENCES_STORAGE_KEY, JSON.stringify(nextPreferences));
};
export const markTutorialSeen = () => {
    const nextPreferences = {
        ...loadTutorialPreferences(),
        hasSeenIntro: true,
    };
    saveTutorialPreferences(nextPreferences);
    return nextPreferences;
};
export const updateTutorialHideOnStartup = (hideOnStartup) => {
    const nextPreferences = {
        ...loadTutorialPreferences(),
        hideOnStartup,
    };
    saveTutorialPreferences(nextPreferences);
    return nextPreferences;
};
export const markTutorialCompleted = (hideOnStartup) => {
    const nextPreferences = {
        ...loadTutorialPreferences(),
        hasSeenIntro: true,
        hideOnStartup,
        lastCompletedAt: new Date().toISOString(),
    };
    saveTutorialPreferences(nextPreferences);
    return nextPreferences;
};
export const createTutorialWorksheet = async () => Excel.run(async (context) => {
    const workbook = context.workbook;
    const worksheetName = 'Reclude Tutorial';
    let worksheet = workbook.worksheets.getItemOrNullObject(worksheetName);
    worksheet.load('isNullObject');
    await context.sync();
    if (worksheet.isNullObject) {
        worksheet = workbook.worksheets.add(worksheetName);
    }
    const targetRange = worksheet.getRange('A1:B6');
    targetRange.values = [
        ['Customer', 'Notes'],
        ['Acme Customer Corp', 'Acme Customer Corp renewed its pricing arrangement this quarter.'],
        ['Northwind Supply', 'Northwind Supply now ships alongside Acme Customer Corp on shared schedules.'],
        ['Fabrikam Foods', 'Fabrikam Foods needs updated onboarding materials before next month.'],
        ['Litware Retail', 'Litware Retail asked for a custom dashboard for the West region.'],
        ['', ''],
    ];
    worksheet.activate();
    const selection = worksheet.getRange('A1:A5');
    selection.select();
    await context.sync();
    return {
        sheetName: worksheetName,
        suggestedSelection: `${quoteSheetName(worksheetName)}!A1:A5`,
    };
});
export const removeTutorialWorksheet = async (sheetName) => Excel.run(async (context) => {
    const worksheet = context.workbook.worksheets.getItemOrNullObject(sheetName);
    worksheet.load('isNullObject');
    await context.sync();
    if (!worksheet.isNullObject) {
        worksheet.delete();
        await context.sync();
    }
});
const quoteSheetName = (sheetName) => `'${sheetName.replace(/'/g, "''")}'`;
