/**
 * Local machine restore-key vault for the active workbook.
 *
 * Office add-ins cannot reliably write directly to arbitrary filesystem paths,
 * so the default restore flow stores one merged key per workbook in local storage.
 */
import { normalizeText } from '@/services/anonymization/matchingService';
const RESTORE_KEY_VAULT_STORAGE_KEY = 'recludeRestoreKeyVaultV1';
const LEGACY_RESTORE_KEY_VAULT_STORAGE_KEY = 'xlsMaskerRestoreKeyVaultV1';
const isRecord = (value) => typeof value === 'object' && value !== null && !Array.isArray(value);
const isRestoreKeyData = (value) => {
    if (!isRecord(value)) {
        return false;
    }
    return (typeof value.version === 'string' &&
        typeof value.workbookGuid === 'string' &&
        typeof value.createdAt === 'string' &&
        Array.isArray(value.taggedRanges) &&
        Array.isArray(value.nameMap));
};
const readVault = () => {
    try {
        const rawValue = localStorage.getItem(RESTORE_KEY_VAULT_STORAGE_KEY) ||
            localStorage.getItem(LEGACY_RESTORE_KEY_VAULT_STORAGE_KEY);
        if (!rawValue) {
            return {
                version: '1.0',
                keysByWorkbookGuid: {},
            };
        }
        const parsed = JSON.parse(rawValue);
        if (!isRecord(parsed) || !isRecord(parsed.keysByWorkbookGuid)) {
            return {
                version: '1.0',
                keysByWorkbookGuid: {},
            };
        }
        const keysByWorkbookGuid = Object.entries(parsed.keysByWorkbookGuid).reduce((accumulator, [workbookGuid, value]) => {
            if (isRestoreKeyData(value)) {
                accumulator[workbookGuid] = value;
            }
            return accumulator;
        }, {});
        return {
            version: typeof parsed.version === 'string' ? parsed.version : '1.0',
            keysByWorkbookGuid,
        };
    }
    catch (_error) {
        return {
            version: '1.0',
            keysByWorkbookGuid: {},
        };
    }
};
const writeVault = (vault) => {
    localStorage.setItem(RESTORE_KEY_VAULT_STORAGE_KEY, JSON.stringify(vault));
};
const getTaggedRangeKey = (taggedRange) => `${taggedRange.address.trim()}::${taggedRange.designation.trim()}`;
const getNameMappingKey = (mapping) => `${mapping.designation}::${mapping.sourceNormalized || normalizeText(mapping.source)}`;
export const mergeRestoreKeys = (existingKeyData, incomingKeyData) => {
    if (!existingKeyData) {
        return incomingKeyData;
    }
    if (existingKeyData.workbookGuid !== incomingKeyData.workbookGuid) {
        return incomingKeyData;
    }
    const taggedRanges = new Map();
    existingKeyData.taggedRanges.forEach((taggedRange) => {
        taggedRanges.set(getTaggedRangeKey(taggedRange), taggedRange);
    });
    incomingKeyData.taggedRanges.forEach((taggedRange) => {
        taggedRanges.set(getTaggedRangeKey(taggedRange), taggedRange);
    });
    const nameMap = new Map();
    existingKeyData.nameMap.forEach((mapping) => {
        nameMap.set(getNameMappingKey(mapping), mapping);
    });
    incomingKeyData.nameMap.forEach((mapping) => {
        nameMap.set(getNameMappingKey(mapping), mapping);
    });
    const mergedKeyData = {
        ...incomingKeyData,
        taggedRanges: [...taggedRanges.values()],
        nameMap: [...nameMap.values()],
    };
    const workbookName = incomingKeyData.workbookName || existingKeyData.workbookName;
    if (workbookName) {
        mergedKeyData.workbookName = workbookName;
    }
    const edgeCaseScanConfig = incomingKeyData.edgeCaseScanConfig || existingKeyData.edgeCaseScanConfig;
    if (edgeCaseScanConfig) {
        mergedKeyData.edgeCaseScanConfig = edgeCaseScanConfig;
    }
    return mergedKeyData;
};
export const loadLocalRestoreKey = (workbookGuid) => {
    const vault = readVault();
    return vault.keysByWorkbookGuid[workbookGuid] ?? null;
};
export const saveLocalRestoreKey = (keyData) => {
    const vault = readVault();
    const mergedKeyData = mergeRestoreKeys(vault.keysByWorkbookGuid[keyData.workbookGuid] ?? null, keyData);
    writeVault({
        ...vault,
        keysByWorkbookGuid: {
            ...vault.keysByWorkbookGuid,
            [keyData.workbookGuid]: mergedKeyData,
        },
    });
    return mergedKeyData;
};
export const replaceLocalRestoreKey = (keyData) => {
    const vault = readVault();
    writeVault({
        ...vault,
        keysByWorkbookGuid: {
            ...vault.keysByWorkbookGuid,
            [keyData.workbookGuid]: keyData,
        },
    });
};
export const clearLocalRestoreKey = (workbookGuid) => {
    const vault = readVault();
    const nextKeysByWorkbookGuid = { ...vault.keysByWorkbookGuid };
    delete nextKeysByWorkbookGuid[workbookGuid];
    writeVault({
        ...vault,
        keysByWorkbookGuid: nextKeysByWorkbookGuid,
    });
};
