const quoteSheetName = (sheetName) => `'${sheetName.replace(/'/g, "''")}'`;
const splitRangeAddress = (address) => {
    const separatorIndex = address.indexOf('!');
    if (separatorIndex === -1) {
        return { rangeAddress: address.trim() };
    }
    const rawSheetName = address.slice(0, separatorIndex).trim();
    const rangeAddress = address.slice(separatorIndex + 1).trim();
    const sheetName = rawSheetName.replace(/^'|'$/g, '').replace(/''/g, "'");
    return {
        sheetName,
        rangeAddress,
    };
};
const resolveRange = (context, address) => {
    const parsed = splitRangeAddress(address);
    if (parsed.sheetName) {
        const worksheet = context.workbook.worksheets.getItem(parsed.sheetName);
        return worksheet.getRange(parsed.rangeAddress);
    }
    const worksheet = context.workbook.worksheets.getActiveWorksheet();
    return worksheet.getRange(parsed.rangeAddress);
};
const hasTextInRow = (row) => row.some((cellValue) => typeof cellValue === 'string' && cellValue.trim().length > 0);
const hasAnyValueInRow = (row) => row.some((cellValue) => {
    if (typeof cellValue === 'string') {
        return cellValue.trim().length > 0;
    }
    return cellValue !== null && cellValue !== undefined && cellValue !== '';
});
export const getSelectedRangeAddress = async () => Excel.run(async (context) => {
    const selectedRange = context.workbook.getSelectedRange();
    selectedRange.load('address');
    await context.sync();
    return selectedRange.address;
});
export const analyzeSelectionAgainstTaggedRanges = async (taggedRanges) => Excel.run(async (context) => {
    const selectedRange = context.workbook.getSelectedRange();
    selectedRange.load('address');
    await context.sync();
    const selectedAddress = selectedRange.address;
    const selectedParts = splitRangeAddress(selectedAddress);
    const loadState = taggedRanges
        .filter((taggedRange) => {
        const taggedRangeParts = splitRangeAddress(taggedRange.address);
        return taggedRangeParts.sheetName === selectedParts.sheetName;
    })
        .map((taggedRange) => {
        const existingRange = resolveRange(context, taggedRange.address);
        const intersection = selectedRange.getIntersectionOrNullObject(existingRange);
        existingRange.load('address');
        intersection.load('isNullObject');
        return {
            taggedRange,
            existingRange,
            intersection,
        };
    });
    await context.sync();
    let exactMatch = null;
    const overlappingTaggedRanges = [];
    loadState.forEach(({ taggedRange, existingRange, intersection }) => {
        if (existingRange.address === selectedAddress) {
            exactMatch = taggedRange;
            return;
        }
        if (!intersection.isNullObject) {
            overlappingTaggedRanges.push(taggedRange);
        }
    });
    return {
        selectionAddress: selectedAddress,
        exactMatch,
        overlappingTaggedRanges,
    };
});
export const deriveEffectiveTaggedRangeAddress = async (selectionAddress, hasHeaders) => Excel.run(async (context) => {
    const selectedRange = resolveRange(context, selectionAddress);
    selectedRange.load('address');
    if (!hasHeaders) {
        await context.sync();
        return selectedRange.address;
    }
    const parsed = splitRangeAddress(selectionAddress);
    const worksheet = parsed.sheetName
        ? context.workbook.worksheets.getItem(parsed.sheetName)
        : context.workbook.worksheets.getActiveWorksheet();
    const usedRange = worksheet.getUsedRangeOrNullObject(true);
    usedRange.load('isNullObject');
    await context.sync();
    if (usedRange.isNullObject) {
        throw new Error('The selected range does not include any populated data.');
    }
    const intersectedRange = selectedRange.getIntersectionOrNullObject(usedRange);
    intersectedRange.load(['isNullObject', 'values', 'rowCount', 'columnCount', 'address']);
    await context.sync();
    if (intersectedRange.isNullObject) {
        throw new Error('The selected range does not include any populated data.');
    }
    const values = intersectedRange.values;
    const headerRowIndex = values.findIndex((row) => hasTextInRow(row));
    if (headerRowIndex === -1) {
        throw new Error('No header row containing text was found inside the selected range.');
    }
    let lastPopulatedRowIndex = -1;
    for (let rowIndex = values.length - 1; rowIndex > headerRowIndex; rowIndex -= 1) {
        if (hasAnyValueInRow(values[rowIndex] ?? [])) {
            lastPopulatedRowIndex = rowIndex;
            break;
        }
    }
    if (lastPopulatedRowIndex === -1) {
        throw new Error('No populated rows remain after removing the header row from the selected range.');
    }
    const bodyRowCount = lastPopulatedRowIndex - headerRowIndex;
    const bodyStart = intersectedRange.getCell(headerRowIndex + 1, 0);
    const effectiveRange = bodyStart.getResizedRange(bodyRowCount - 1, intersectedRange.columnCount - 1);
    effectiveRange.load('address');
    await context.sync();
    const effectiveParts = splitRangeAddress(effectiveRange.address);
    if (effectiveParts.sheetName) {
        return `${quoteSheetName(effectiveParts.sheetName)}!${effectiveParts.rangeAddress}`;
    }
    return effectiveRange.address;
});
